package com.seaquake6324.civitas.infrastructure.population;

import com.seaquake6324.civitas.application.StartOutMigrationService;
import com.seaquake6324.civitas.domain.City;
import com.seaquake6324.civitas.domain.building.BuildingStatus;
import com.seaquake6324.civitas.domain.civilization.CivilizationLayer;
import com.seaquake6324.civitas.domain.population.*;
import com.seaquake6324.civitas.infrastructure.config.CivitasConfig;
import com.seaquake6324.civitas.infrastructure.entity.CitizenEntity;
import com.seaquake6324.civitas.infrastructure.entity.MaterializationLeaseManager;
import com.seaquake6324.civitas.infrastructure.persistence.*;
import java.nio.charset.StandardCharsets;
import java.util.*;
import net.minecraft.core.BlockPos;
import net.minecraft.network.chat.Component;
import net.minecraft.server.MinecraftServer;
import net.minecraft.server.level.ServerLevel;

/** Bounded server-thread evaluation of settled NPC families that may physically leave their city. */
public final class OutMigrationManager {
 private static final OutMigrationRules RULES=new OutMigrationRules();private static final StartOutMigrationService START=new StartOutMigrationService();
 private static MinecraftServer owner;private static long nextRun,runs,householdsExamined,singlesExamined,eligible,rolls,started,rollFailures,missingPosition,playerFamiliesSkipped,conflicts,capStops,totalMicros,maxMicros;private static String lastReason="not_run",lastEvaluation="none";
 public static void tick(MinecraftServer server){if(owner!=server)reset(server);long now=server.overworld().getGameTime();if(now<nextRun)return;nextRun=now+CivitasConfig.OUT_MIGRATION_INTERVAL_TICKS.get();long began=System.nanoTime();runs++;PopulationSavedData p=PopulationSavedData.get(server);CitySavedData cities=CitySavedData.get(server);if(p.readOnly()||cities.readOnly()){lastReason="dependency_read_only";finish(began);return;}int remaining=CivitasConfig.OUT_MIGRATION_STARTS_PER_RUN.get();var hb=p.householdBatch(p.outMigrationHouseholdCursor(),CivitasConfig.OUT_MIGRATION_HOUSEHOLDS_PER_RUN.get());for(Household h:hb.records()){householdsExamined++;if(remaining>0&&household(server,p,cities,h,now))remaining--;}p.outMigrationHouseholdCursor(hb.wrapped()?null:hb.nextCursor());var cb=p.citizenBatch(p.outMigrationCitizenCursor(),CivitasConfig.OUT_MIGRATION_CITIZENS_PER_RUN.get());for(CitizenRecord c:cb.records()){singlesExamined++;if(remaining>0&&c.householdId()==null&&evaluate(server,p,cities,null,List.of(c),Set.of(),Set.of(),Set.of(),now))remaining--;}p.outMigrationCitizenCursor(cb.wrapped()?null:cb.nextCursor());finish(began);}
 private static boolean household(MinecraftServer server,PopulationSavedData p,CitySavedData cities,Household h,long now){Set<FamilyMemberRef> refs=new HashSet<>();refs.addAll(h.partners());refs.addAll(h.guardians());if(refs.stream().anyMatch(r->r.kind()==FamilyMemberRef.Kind.PLAYER)){playerFamiliesSkipped++;lastReason="player_family_deferred";return false;}Set<UUID> members=new HashSet<>(h.children()),partners=new HashSet<>(),guardians=new HashSet<>();h.partners().forEach(r->partners.add(r.id()));h.guardians().forEach(r->guardians.add(r.id()));members.addAll(partners);members.addAll(guardians);if(members.isEmpty()||members.size()>MigrationGroupRecord.HARD_MEMBER_CAP){lastReason="invalid_family_size";return false;}List<CitizenRecord> records=new ArrayList<>();for(UUID id:members){CitizenRecord c=p.citizen(id).orElse(null);if(c==null||!c.alive()||!h.cityId().equals(c.cityId())||!h.id().equals(c.householdId())){lastReason="family_inconsistent";return false;}records.add(c);}return evaluate(server,p,cities,h,records,partners,guardians,h.children(),now);}
 private static boolean evaluate(MinecraftServer server,PopulationSavedData p,CitySavedData cities,Household h,List<CitizenRecord> records,Set<UUID> partners,Set<UUID> guardians,Set<UUID> children,long now){if(records.isEmpty()||records.stream().anyMatch(c->!c.alive()||c.cityId()==null||c.runtimeState()==CitizenRuntimeState.LOCKED)){lastReason="citizen_ineligible";return false;}UUID cityId=records.getFirst().cityId();if(records.stream().anyMatch(c->!cityId.equals(c.cityId()))){lastReason="mixed_city";return false;}City city=cities.byId(cityId).orElse(null);if(city==null){lastReason="city_missing";return false;}ServerLevel level=level(server,city.dimension());if(level==null){lastReason="dimension_missing";return false;}Map<UUID,Long> positions=new LinkedHashMap<>();for(CitizenRecord c:records){Long pos=position(server,p,c,city);if(pos==null){missingPosition++;lastReason="position_missing";return false;}positions.put(c.id(),pos);}double migration=records.stream().mapToDouble(CitizenRecord::migrationWillingness).average().orElse(0),settlement=records.stream().mapToDouble(CitizenRecord::settlementWillingness).average().orElse(100),safety=records.stream().mapToInt(c->c.needs().safety()).average().orElse(50),food=h==null?records.stream().mapToInt(c->c.needs().food()).average().orElse(50):h.foodCoverage(),housing=h==null?(records.getFirst().residenceId()==null?0:100):h.housingCoverage();var civ=CivilizationSavedData.get(server).get(city.dimension(),city.coreChunk(),CivilizationLayer.SURFACE);var result=RULES.evaluate(new OutMigrationRules.Inputs(migration,settlement,housing,food,safety,civ.civility(),civ.activity()),CivitasConfig.OUT_MIGRATION_MAX_CHANCE.get());eligible++;rolls++;lastEvaluation="city="+city.name()+",score="+one(result.score())+",chance="+one(result.chance()*100)+"%,parts="+result.components();UUID seed=h==null?records.getFirst().id():h.id();if(roll(seed,now)>=result.chance()){rollFailures++;lastReason="pressure_roll_failed";return false;}if(p.activeMigrationCount()>=CivitasConfig.MIGRATION_ACTIVE_GROUP_CAP.get()){capStops++;lastReason="active_cap";return false;}BlockPos exit=MigrationManager.findOrigin(level,cities,city,now^seed.getLeastSignificantBits());if(exit==null){missingPosition++;lastReason="no_loaded_exit";return false;}Set<UUID> memberIds=new HashSet<>();Map<UUID,Long> revisions=new HashMap<>();for(CitizenRecord c:records){memberIds.add(c.id());revisions.put(c.id(),c.revision());}UUID groupId=UUID.nameUUIDFromBytes((cityId+":out:"+seed+":"+now).getBytes(StandardCharsets.UTF_8));var group=new MigrationGroupRecord(groupId,cityId,city.dimension(),exit.asLong(),city.corePosition(),memberIds,partners,guardians,children,positions,MigrationGroupRecord.State.DEPARTING,result.score(),now,now,1);if(!START.start(p,group,h,revisions,CivitasConfig.MIGRATION_ACTIVE_GROUP_CAP.get()).success()){conflicts++;lastReason="stale_or_conflict";return false;}started++;lastReason="departure_started";String names=records.stream().map(CitizenRecord::displayName).sorted().reduce((a,b)->a+", "+b).orElse("?");for(var player:server.getPlayerList().getPlayers())if(city.mayManage(player.getUUID()))player.sendSystemMessage(Component.translatable("civitas.migration.departing",names),true);return true;}
 private static Long position(MinecraftServer server,PopulationSavedData p,CitizenRecord c,City city){var lease=MaterializationLeaseManager.lease(c.id()).orElse(null);if(lease!=null)for(ServerLevel level:server.getAllLevels()){var entity=level.getEntity(lease.entityId());if(entity instanceof CitizenEntity)return entity.blockPosition().asLong();}var saved=p.location(c.id()).orElse(null);if(saved!=null&&city.id().equals(saved.cityId())&&city.dimension().equals(saved.dimension()))return saved.position();if(c.residenceId()!=null){var b=BuildingSavedData.get(server).byId(c.residenceId()).orElse(null);if(b!=null&&b.status()==BuildingStatus.VALID&&city.id().equals(b.cityId())&&city.dimension().equals(b.dimension()))return b.interior();}return null;}
 private static ServerLevel level(MinecraftServer server,String dimension){for(ServerLevel level:server.getAllLevels())if(level.dimension().identifier().toString().equals(dimension))return level;return null;}private static double roll(UUID id,long now){return new SplittableRandom(id.getMostSignificantBits()^Long.rotateLeft(id.getLeastSignificantBits(),11)^now).nextDouble();}private static String one(double value){return String.format(Locale.ROOT,"%.1f",value);}private static void finish(long began){long micros=Math.max(0,(System.nanoTime()-began)/1_000);totalMicros+=micros;maxMicros=Math.max(maxMicros,micros);}
 private static void reset(MinecraftServer server){owner=server;nextRun=0;runs=householdsExamined=singlesExamined=eligible=rolls=started=rollFailures=missingPosition=playerFamiliesSkipped=conflicts=capStops=totalMicros=maxMicros=0;lastReason="server_reset";lastEvaluation="none";}public static Metrics metrics(){return new Metrics(runs,householdsExamined,singlesExamined,eligible,rolls,started,rollFailures,missingPosition,playerFamiliesSkipped,conflicts,capStops,totalMicros/Math.max(1,runs),maxMicros,lastReason,lastEvaluation);}public record Metrics(long runs,long householdsExamined,long singlesExamined,long eligible,long rolls,long started,long rollFailures,long missingPosition,long playerFamiliesSkipped,long conflicts,long capStops,long averageMicros,long maxMicros,String lastReason,String lastEvaluation){}private OutMigrationManager(){}
}
